Requirements:
1. Etymology (Origin).
2. 3 Synonyms in ${entry.sourceLang}.
3. 3 Variations in ${entry.targetLang}.
4. 2 Literature quotes in ${entry.sourceLang} with translations.
5. 2 Idioms/Natural sentences in ${entry.sourceLang} with translations.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            etymology: { type: Type.STRING },
            synonyms: { type: Type.ARRAY, items: { type: Type.STRING } },
            variations: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  confidence: { type: Type.NUMBER }
                }
              }
            },
            usage: { type: Type.STRING },
            literature: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  translation: { type: Type.STRING },
                  source: { type: Type.STRING },
                  author: { type: Type.STRING }
                }
              }
            },
            idioms: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  translation: { type: Type.STRING },
                  context: { type: Type.STRING }
                }
              }
            }
          }
        }
      }
    });

    const raw = JSON.parse(response.text || '{}');
    return {
      synonyms: raw.synonyms || [],
      variations: (raw.variations || []).map((v: any) => ({ ...v, source: 'ai' })),
      philology: { ...entry.philology, etymology: raw.etymology || "Archival record updated." },
      culture: {
        usage: raw.usage || "Standard scholarly use",
        register: 'neutral',
        notes: ""
      },
      literature: raw.literature || [],
      realLifeSentences: raw.idioms || [], 
      idioms: raw.idioms || []
    };
  } catch (err) {
    return {};
  }
}

