/**
 * Arena Quiz Generation
 */
export async function generateQuiz(entries: LexicalEntry[]) {
  const apiKey = getApiKey();
  const ai = new GoogleGenAI({ apiKey });
  const context = entries.map(e => `${e.term} <-> ${e.mainTranslation}`).join(", ");

  const prompt = `Create a 3-option multiple-choice quiz for: ${context}. JSON Array.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              question: { type: Type.STRING },
              correctAnswer: { type: Type.STRING },
              options: { type: Type.ARRAY, items: { type: Type.STRING } },
              explanation: { type: Type.STRING }
            },
            required: ["question", "correctAnswer", "options", "explanation"]
          }
        }
      }
    });

    const questions = JSON.parse(response.text || '[]');
    return questions.map((q: any) => ({
      ...q,
      options: shuffleArray(q.options)
    }));
  } catch (err) {
    return [];
  }
}

