export async function fetchSuggestions(query: string, sourceLang: Language): Promise<string[]> {
  const cleanQuery = query.toLowerCase().trim();
  if (cleanQuery.length < 2) return [];
  const cacheKey = `${sourceLang}:${cleanQuery}`;
  if (suggestionCache.has(cacheKey)) return suggestionCache.get(cacheKey)!;

  try {
    const { data, error } = await supabase
      .from('lex_entries')
      .select('term')
      .eq('source_lang', sourceLang)
      .ilike('normalized_term', `${cleanQuery}%`)
      .limit(5);

    if (error) return [];
    const results = Array.from(new Set(data?.map(d => (d as any).term).filter(Boolean) as string[]));
    suggestionCache.set(cacheKey, results);
    return results;
  } catch {
    return [];
  }
}

export async function fetchGlobalEntry(
  normalizedTerm: string,
  sourceLang: Language,
  targetLang: Language
): Promise<LexicalEntry | null> {
  const fetchPromise = (async () => {
    try {
      const { data, error } = await supabase
        .from('lex_entries')
        .select('entry_data')
        .eq('normalized_term', normalizedTerm)
        .eq('source_lang', sourceLang)
        .eq('target_lang', targetLang)
        .maybeSingle();
      if (error) return null;
      return (data?.entry_data as LexicalEntry) || null;
    } catch {
      return null;
    }
  })();

  // If DB doesn't respond in 1s, we return null so the app proceeds to AI.
  return withTimeout(fetchPromise, 1000, null);
}

