    await supabase.from('lex_user_history').upsert({
      telegram_id: telegramId,
      entry_id: entry.id,
      entry_data: entry,
      created_at: new Date().toISOString()
    }, { onConflict: 'telegram_id, entry_id' });
  } catch {}
}

export async function upsertProfile(profile: UserProfile) {
  if (!profile.telegramId) return;
  try {
    await supabase.from('lex_profiles').upsert({ 
      telegram_id: profile.telegramId,
      username: profile.username || 'Scholar',
      profile_data: profile,
      updated_at: new Date().toISOString() 
    }, { onConflict: 'telegram_id' });
  } catch {}
}

import { GoogleGenAI, Type } from "@google/genai";
import { Language, LexicalEntry } from "../types";

const generateId = () => {
  if (typeof crypto !== 'undefined' && crypto.randomUUID) {
    return crypto.randomUUID();
  }
  return 'lex-' + Date.now() + '-' + Math.random().toString(36).substring(2, 11);
};

function shuffleArray<T>(array: T[]): T[] {
  const newArray = [...array];
  for (let i = newArray.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [newArray[i], newArray[j]] = [newArray[j], newArray[i]];
  }
  return newArray;
}

const getApiKey = () => {
  try {
    return process.env.API_KEY;
  } catch (e) {
    return (window as any).process?.env?.API_KEY || "";
  }
};

/**
 * PHASE 1: Lightning Core (Priority 1)
 * Optimized for < 1.5s generation.
 */
export async function translateWordCore(
  query: string, 
  sourceLanguage: Language, 
  targetLanguage: Language
): Promise<LexicalEntry> {
  const apiKey = getApiKey();
  const ai = new GoogleGenAI({ apiKey });

  const prompt = `Translate "${query}" from ${sourceLanguage} to ${targetLanguage}.
JSON format. 
{term, mainTranslation, partOfSpeech, gender, cefrLevel}`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      thinkingConfig: { thinkingBudget: 0 },
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          term: { type: Type.STRING },
          mainTranslation: { type: Type.STRING },
          partOfSpeech: { type: Type.STRING },
          gender: { type: Type.STRING },
          cefrLevel: { type: Type.STRING }
        },
        required: ["term", "mainTranslation", "partOfSpeech"]
      }
    }
  });

  const rawData = JSON.parse(response.text || '{}');

  return {
    id: generateId(),
    term: rawData.term || query,
    normalizedTerm: query.toLowerCase().trim(),
    mainTranslation: rawData.mainTranslation,
    sourceLang: sourceLanguage,
    targetLang: targetLanguage,
    cefrLevel: rawData.cefrLevel,
    philology: {
      etymology: "", 
      partOfSpeech: rawData.partOfSpeech,
      gender: rawData.gender
    },
    culture: { usage: "", register: 'neutral', notes: "" },
    synonyms: [],
    variations: [],
    literature: [],
    realLifeSentences: [],
    idioms: [],
    timestamp: Date.now()
  };
}

/**
 * PHASE 2: Background Hydration (Priority 2)
 * Fetches philology and cultural context.
 */
export async function enrichLexicalEntry(entry: LexicalEntry): Promise<Partial<LexicalEntry>> {
  const apiKey = getApiKey();
  const ai = new GoogleGenAI({ apiKey });

  const prompt = `Provide etymology, 3 synonyms, 2 usage examples, and 1 literary quote for "${entry.term}" (${entry.sourceLang} -> ${entry.targetLang}). JSON format.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            etymology: { type: Type.STRING },
            synonyms: { type: Type.ARRAY, items: { type: Type.STRING } },
            variations: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  confidence: { type: Type.NUMBER }
                }
              }
            },
            usage: { type: Type.STRING },
            literature: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  translation: { type: Type.STRING },
                  source: { type: Type.STRING },
                  author: { type: Type.STRING }
                }
              }
            },
            idioms: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  text: { type: Type.STRING },
                  translation: { type: Type.STRING },
                  context: { type: Type.STRING }
                }
              }
            }
          }
        }
      }
    });

    const raw = JSON.parse(response.text || '{}');
    return {
      synonyms: raw.synonyms || [],
      variations: (raw.variations || []).map((v: any) => ({ ...v, source: 'ai' })),
      philology: { ...entry.philology, etymology: raw.etymology },
      culture: {
        usage: raw.usage,
        register: 'neutral',
        notes: ""
      },
      literature: raw.literature || [],
      idioms: raw.idioms || []
    };
  } catch {
    return {};
  }
}

export async function getDailyInsight() {
  const apiKey = getApiKey();
  const ai = new GoogleGenAI({ apiKey });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: "Linguistic fact about German or Uzbek in JSON {title, fact}.",
      config: {
        thinkingConfig: { thinkingBudget: 0 },
        responseMimeType: "application/json"
      }
    });
    return JSON.parse(response.text || '{}');
  } catch {
    return { title: "Lexical Roots", fact: "Words carry history." };
  }
}

export async function generateQuiz(entries: LexicalEntry[]) {
  const apiKey = getApiKey();
  const ai = new GoogleGenAI({ apiKey });
  const context = entries.map(e => `${e.term}:${e.mainTranslation}`).join(",");
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Create a 3-question MCQ quiz for: ${context}. JSON Array.`,
      config: {
        thinkingConfig: { thinkingBudget: 0 },
        responseMimeType: "application/json"
      }
    });
    const questions = JSON.parse(response.text || '[]');
    return questions.map((q: any) => ({ ...q, options: shuffleArray(q.options) }));
  } catch {
    return [];
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { Language, LexicalEntry, UserProfile } from '../types';
import { translateWordCore, enrichLexicalEntry } from '../services/gemini';
import { speak, resumeAudioContext } from '../services/tts';
import { SEED_ARCHIVE } from '../constants';
import { fetchGlobalEntry, saveGlobalEntry, fetchSuggestions } from '../services/supabase';
import { triggerHaptic } from '../services/telegram';
import ResultCard from './ResultCard';
import HistoryGrid from './HistoryGrid';

interface Props {
  onEntrySaved: (entry: LexicalEntry) => void;
  autoAudio: boolean;
  setAutoAudio: (val: boolean) => void;
  profile: UserProfile;
  history: LexicalEntry[];
  onStartArena: () => void;
  selectedEntry?: LexicalEntry | null;
  onEntryClick: (entry: LexicalEntry) => void;
}

interface SuggestionItem {
  term: string;
  source: 'local' | 'global' | 'seed';
}

const LANGUAGES: Record<Language, string> = {
  German: 'GER',
  Uzbek: 'UZB',
  English: 'ENG',
  Russian: 'RUS',
  Arabic: 'ARA'
};

const LANGUAGES_LIST: Language[] = ['German', 'Uzbek', 'English', 'Russian', 'Arabic'];

const normalize = (text: string, lang: Language): string => {
  let res = text.trim().toLowerCase();
  if (lang === 'German') {
    res = res.replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue').replace(/ß/g, 'ss');
  } else if (lang === 'Uzbek') {
    res = res.replace(/[‘’`]/g, "'");
  }
  return res;
};

const Dictionary: React.FC<Props> = ({ 
  onEntrySaved, 
  autoAudio, 
  setAutoAudio, 
  profile, 
  history, 
  selectedEntry,
  onEntryClick,
  onStartArena
}) => {
  const [query, setQuery] = useState('');
  const [sourceLang, setSourceLang] = useState<Language>(() => (localStorage.getItem('lexSourceLang') as Language) || 'German');
  const [targetLang, setTargetLang] = useState<Language>(() => (localStorage.getItem('lexTargetLang') as Language) || 'Uzbek');
  const [loading, setLoading] = useState(false);
  const [isListening, setIsListening] = useState(false);
  const [voiceSupported, setVoiceSupported] = useState(true);
  const [voiceStatusMsg, setVoiceStatusMsg] = useState<string | null>(null);
  const [result, setResult] = useState<LexicalEntry | null>(null);
  const [suggestions, setSuggestions] = useState<SuggestionItem[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);
  const [selectedIndex, setSelectedIndex] = useState(-1);
  const [searchError, setSearchError] = useState<string | null>(null);

  const suggestionRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) setVoiceSupported(false);
  }, []);

  useEffect(() => {
    if (selectedEntry) {
      setQuery(selectedEntry.term);
      setResult(selectedEntry);
      setSourceLang(selectedEntry.sourceLang);
      setTargetLang(selectedEntry.targetLang);
      setShowSuggestions(false);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [selectedEntry]);

  useEffect(() => {
    if (loading || query.trim().length < 2) {
      setSuggestions([]);
      setShowSuggestions(false);
      return;
    }

    const delayDebounce = setTimeout(async () => {
      const trimmedQuery = query.trim().toLowerCase();
      const localMatches = history
        .filter(e => e.sourceLang === sourceLang && e.term.toLowerCase().startsWith(trimmedQuery))
        .map(e => ({ term: e.term, source: 'local' as const }));

      const seedMatches = Object.values(SEED_ARCHIVE)
        .filter(e => e?.term && e.term.toLowerCase().startsWith(trimmedQuery))
        .map(e => ({ term: e!.term!, source: 'seed' as const }));

      let globalMatches: SuggestionItem[] = [];
      if (localMatches.length + seedMatches.length < 3) {
        try {
          const globalTerms = await fetchSuggestions(query, sourceLang);
          globalMatches = globalTerms.map(term => ({ term, source: 'global' as const }));
        } catch (e) {}
      }

      const combined = [...localMatches, ...seedMatches, ...globalMatches];
      const unique = combined.filter((v, i, a) => 
        a.findIndex(t => t.term.toLowerCase() === v.term.toLowerCase()) === i
      ).slice(0, 5);

      setSuggestions(unique);
      setShowSuggestions(unique.length > 0);
    }, 250);
    return () => clearTimeout(delayDebounce);
  }, [query, sourceLang, history, loading]);

  const handleSourceLangChange = (lang: Language) => {
    setSourceLang(lang);
    localStorage.setItem('lexSourceLang', lang);
  };

  const handleTargetLangChange = (lang: Language) => {
    setTargetLang(lang);
    localStorage.setItem('lexTargetLang', lang);
  };

  const handleSearch = async (overrideQuery?: string) => {
    const cleanQuery = (overrideQuery || query).trim();
    if (!cleanQuery) return;

    setShowSuggestions(false);
    setSearchError(null);
    if (inputRef.current) inputRef.current.blur();
    setQuery(cleanQuery);

    const normQuery = normalize(cleanQuery, sourceLang);
    const localHit = history.find(e => normalize(e.term, e.sourceLang) === normQuery && e.sourceLang === sourceLang && e.targetLang === targetLang);

    if (localHit) {
      setResult(localHit);
      if (autoAudio) speak(cleanQuery, sourceLang).then(() => speak(localHit.mainTranslation, targetLang));
      return;
    }

    setLoading(true);
    setResult(null);

    try {
      // 1. Race Database check against AI startup
      const globalHit = await fetchGlobalEntry(normQuery, sourceLang, targetLang);

      if (globalHit) {
        setResult(globalHit);
        setLoading(false);
        onEntrySaved(globalHit);
        if (autoAudio) speak(cleanQuery, sourceLang).then(() => speak(globalHit.mainTranslation, targetLang));
        return;
      }

      // 2. Fast AI Core (Phase 1)
      const coreEntry = await translateWordCore(cleanQuery, sourceLang, targetLang);
      coreEntry.normalizedTerm = normQuery;
      setResult(coreEntry);
      setLoading(false);

      if (autoAudio) speak(cleanQuery, sourceLang).then(() => speak(coreEntry.mainTranslation, targetLang));

      // 3. Lazy Hydration (Phase 2)
      const enrichment = await enrichLexicalEntry(coreEntry);
      const fullEntry = { ...coreEntry, ...enrichment };
      setResult(fullEntry);
      onEntrySaved(fullEntry);
      saveGlobalEntry(fullEntry);

    } catch (err) {
      setSearchError("The archive connection is interrupted.");
      setLoading(false);
    }
  };

  return (
    <div className="space-y-8 md:space-y-16 max-w-7xl mx-auto contain-layout">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-8 pt-4">
        <div className="flex items-center gap-6">
          <div className="space-y-1 border-l-[3px] border-[#7c1a1a] pl-4">
            <span className="text-[9px] uppercase tracking-[0.4em] text-stone-500 font-black">Philological Mastery</span>
            <div className="flex items-baseline gap-2">
              <span className="text-2xl md:text-3xl font-black serif text-stone-900 leading-none">{profile.xp}</span>
              <span className="text-[8px] uppercase tracking-[0.2em] text-stone-400 font-bold">Total XP</span>
            </div>
          </div>
        </div>

        <div className="flex flex-col lg:flex-row items-center gap-6 lg:gap-12 w-full md:w-auto">
          <div className="flex flex-col sm:flex-row items-center gap-4 bg-stone-100/50 p-2 rounded-sm w-full sm:w-auto border border-stone-200">
             <div className="grid grid-cols-5 bg-white shadow-md overflow-hidden rounded-sm w-full sm:w-auto ring-1 ring-stone-200">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={full} onClick={() => handleSourceLangChange(full)} className={`px-4 py-3 text-[10px] sm:text-[11px] font-black tracking-widest transition-colors ${sourceLang === full ? 'bg-stone-900 text-white' : 'text-stone-400 hover:text-stone-700'}`}>
                    {short}
                  </button>
                ))}
             </div>
             <div className="grid grid-cols-5 bg-white shadow-md overflow-hidden rounded-sm w-full sm:w-auto ring-1 ring-stone-200">
                {(Object.entries(LANGUAGES) as [Language, string][]).map(([full, short]) => (
                  <button key={full} onClick={() => handleTargetLangChange(full)} className={`px-4 py-3 text-[10px] sm:text-[11px] font-black tracking-widest transition-colors ${targetLang === full ? 'bg-[#7c1a1a] text-white' : 'text-stone-400 hover:text-stone-700'}`}>
                    {short}
                  </button>
                ))}
             </div>
          </div>
          <button onClick={() => setAutoAudio(!autoAudio)} className={`flex items-center gap-4 px-5 py-2.5 rounded-full border transition-all ${autoAudio ? 'bg-[#7c1a1a]/5 border-[#7c1a1a]/40' : 'bg-stone-50 border-stone-200'}`}>
            <span className={`text-[11px] uppercase tracking-[0.2em] font-black ${autoAudio ? 'text-[#7c1a1a]' : 'text-stone-500'}`}>AUTO-AUDIO</span>
            <div className={`w-3.5 h-3.5 rounded-full ${autoAudio ? 'bg-[#7c1a1a] shadow-[0_0_10px_rgba(124,26,26,0.4)]' : 'bg-stone-300'}`} />
          </button>
        </div>
      </div>

      <div className="relative w-full" ref={suggestionRef}>
        <form onSubmit={(e) => { e.preventDefault(); handleSearch(); }}>
          <div className={`bg-white border-2 transition-all rounded-sm overflow-hidden flex items-stretch min-h-[70px] md:min-h-[110px] ${loading ? 'opacity-70 pointer-events-none' : 'border-stone-200 shadow-md focus-within:border-stone-400'}`}>
            <input 
              ref={inputRef}
              type="text" 
              value={query} 
              onChange={(e) => setQuery(e.target.value)} 
              onFocus={() => { if (suggestions.length > 0) setShowSuggestions(true); }}
              onKeyDown={(e) => { if (e.key === 'Enter') handleSearch(); }}
              placeholder="Summon an inscription..."
              className="flex-1 min-w-0 px-6 md:px-10 text-2xl md:text-6xl serif bg-transparent outline-none text-stone-900 lowercase" 
            />
            <button type="submit" className="px-5 md:px-10 flex flex-shrink-0 items-center justify-center bg-white text-[#7c1a1a]">
              {loading ? <div className="w-8 h-8 border-4 border-[#7c1a1a] border-t-transparent rounded-full animate-spin" /> : <svg xmlns="http://www.w3.org/2000/svg" className="w-8 h-8 md:w-12 md:h-12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3.5"><line x1="5" y1="12" x2="19" y2="12"></line><polyline points="12 5 19 12 12 19"></polyline></svg>}
            </button>
          </div>
        </form>
        {showSuggestions && (
          <div className="absolute top-full left-0 right-0 bg-white border-2 border-stone-200 shadow-2xl z-20 rounded-b-sm">
             {suggestions.map((s, idx) => (
               <button key={idx} onClick={() => handleSearch(s.term)} className="w-full text-left px-10 py-6 border-b border-stone-100 last:border-0 hover:bg-stone-50 flex items-center justify-between">
                 <span className="serif text-2xl md:text-3xl text-stone-700">{s.term}</span>
                 <span className="text-[9px] uppercase tracking-widest font-black text-stone-300">{s.source}</span>
               </button>
             ))}
          </div>
        )}
      </div>

      <div className="min-h-[60px]">
        {loading && (
          <div className="bg-white border border-stone-100 p-16 flex flex-col items-center justify-center space-y-8">
            <div className="w-20 h-20 border-[5px] border-[#7c1a1a] border-t-transparent rounded-full animate-spin"></div>
            <p className="serif text-3xl italic text-stone-300">Consulting the Lexicon...</p>
          </div>
        )}
        {searchError && (
          <div className="bg-[#7c1a1a] text-stone-100 p-12 rounded-sm shadow-xl">
             <h3 className="text-3xl serif font-black mb-4">The Archive is Silent.</h3>
             <p className="opacity-80 mb-8">{searchError}</p>
             <button onClick={() => handleSearch()} className="px-10 py-4 bg-white text-[#7c1a1a] text-[11px] font-black uppercase tracking-[0.4em]">Retry Invocation</button>
          </div>
        )}
        {result && <ResultCard entry={result} onSearchTerm={(term) => handleSearch(term)} />}
      </div>

      <div className="pt-16 border-t border-stone-100">
        <HistoryGrid history={history} onEntryClick={onEntryClick} />
      </div>
    </div>
  );
};

export default Dictionary;
